const topics = [
  { topic: 'AML compliance Malta', keyword: 'AML compliance Malta real estate' },
  { topic: 'Lead scoring AI for real estate', keyword: 'lead scoring AI real estate Malta' },
  { topic: 'Malta real estate market 2026', keyword: 'Malta real estate market 2026' },
  { topic: 'WhatsApp automation for real estate agents', keyword: 'WhatsApp automation real estate agents' },
  { topic: 'Real estate productivity tools Malta', keyword: 'real estate productivity tools Malta' },
  { topic: 'AI listing descriptions', keyword: 'AI listing descriptions real estate' },
  { topic: 'Housing Authority compliance Malta', keyword: 'Housing Authority Malta compliance agent' },
  { topic: 'CRM for solo agents Malta', keyword: 'CRM solo real estate agents Malta' },
  { topic: 'Real estate follow-up automation', keyword: 'real estate follow-up automation Malta' },
  { topic: 'PropTech Malta', keyword: 'PropTech Malta real estate technology' },
  { topic: 'Real estate agent burnout solutions', keyword: 'real estate agent burnout automation' },
  { topic: 'REAPA AI features', keyword: 'REAPA AI real estate Malta platform' }
];

const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const weekNumber = Math.floor((now - startOfYear) / (7 * 24 * 60 * 60 * 1000));
const selected = topics[weekNumber % topics.length];

return [{ json: selected }];

const response = $input.first().json;
const mdxContent = response.content[0].text;

const titleMatch = mdxContent.match(/title:\s*["'](.+?)["']/);
const title = titleMatch ? titleMatch[1] : 'New Blog Post';

const slug = title
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .slice(0, 60);

const base64Content = Buffer.from(mdxContent).toString('base64');

return [{ json: { mdxContent, title, slug, base64Content } }];

